class Solution {
public:
    vector<int> fib(int n) {
        if (n <= 2) return {0, 1};
        vector<int> res(n);
        res[0] = 0;
        res[1] = 1;
        for (int i = 2; i < n; i++) {
            res[i] = res[i - 1] + res[i - 2] + 1;
        }
        return res;
    }
};

